/* Suggested markup: <div class="uiwiki-horizontal-feature-chapters" tabindex="0"><span>Horizontal Feature Chapters</span></div> */
.uiwiki-horizontal-feature-chapters {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-horizontal-feature-chapters > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #53e8d4;
  animation: horizontal_feature_chapters 1.8s ease-in-out infinite alternate;
}
.uiwiki-horizontal-feature-chapters:hover,
.uiwiki-horizontal-feature-chapters:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes horizontal_feature_chapters {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-horizontal-feature-chapters, .uiwiki-horizontal-feature-chapters > span { animation: none; transition: none; }
}
